#!/usr/bin/env python
import os
import sys
from subprocess import check_call

def main():
    # Install all requirements using pip install -r requirements.txt without hash verification for speed
    check_call(['pip', 'install', '-r', 'requirements.txt', '--no-cache-dir'])
    
    # Upgrade packages to latest versions with --upgrade flag
    check_call(['pip', 'list', '--outdated'], stdout=sys.stdout)
    outdated = [line.strip() for line in sys.stdout]
    if len(outdated) > 0:
        check_call(['pip', 'install', '--upgrade'] + outdated)

if __name__ == '__main__':
    main()